import numpy as np

class Layer:
    def __init__(self):
        self.params = {}
        self.grads = {}

    def forward(self, X):
        raise NotImplementedError

    def backward(self, dA_prev):
        raise NotImplementedError

class Dense(Layer):
    def __init__(self, n_inputs, n_neurons, weight_scale=0.01):
        super().__init__()
        self.params['W'] = weight_scale * np.random.randn(n_inputs, n_neurons)
        self.params['b'] = np.zeros((1, n_neurons))
        self.X = None

    def forward(self, X):
        self.X = X
        return np.dot(X, self.params['W']) + self.params['b']

    def backward(self, dA_prev):
        m = self.X.shape[0]
        dW = np.dot(self.X.T, dA_prev) / m
        db = np.sum(dA_prev, axis=0, keepdims=True) / m
        dX_prev = np.dot(dA_prev, self.params['W'].T)

        self.grads['W'] = dW
        self.grads['b'] = db

        return dX_prev

class Activation(Layer):
    def __init__(self, activation_type):
        super().__init__()
        self.activation_type = activation_type
        self.A = None

    def forward(self, Z):
        self.A = self._activate(Z)
        return self.A

    def backward(self, dA_prev):
        dZ = dA_prev * self._derivative()
        return dZ

    def _activate(self, Z):
        if self.activation_type == 'relu':
            return np.maximum(0, Z)
        elif self.activation_type == 'sigmoid':
            return 1 / (1 + np.exp(-Z))
        elif self.activation_type == 'tanh':
            return np.tanh(Z)
        else:
            raise ValueError("Invalid activation type")

    def _derivative(self):
        if self.activation_type == 'relu':
            return (self.A > 0).astype(float)
        elif self.activation_type == 'sigmoid':
            return self.A * (1 - self.A)
        elif self.activation_type == 'tanh':
            return 1 - np.square(self.A)
        else:
            raise ValueError("Invalid activation type")

class Softmax(Layer):
    def __init__(self):
        super().__init__()
        self.probs = None

    def forward(self, Z):
        exp_Z = np.exp(Z - np.max(Z, axis=1, keepdims=True))
        self.probs = exp_Z / np.sum(exp_Z, axis=1, keepdims=True)
        return self.probs

    def backward(self, Y):
        return self.probs - Y

class Model:
    def __init__(self, layers):
        self.layers = layers

    def forward(self, X):
        A = X
        for layer in self.layers:
            A = layer.forward(A)
        return A

    def backward(self, Y):
        dA_prev = Y
        for layer in reversed(self.layers):
            dA_prev = layer.backward(dA_prev)

    def update_params(self, learning_rate):
        for layer in self.layers:
            for key, grad in layer.grads.items():
                layer.params[key] -= learning_rate * grad

    def predict(self, X):
        return self.forward(X)

def mse_loss(Y_hat, Y):
    return np.mean(np.square(Y_hat - Y))

def mse_loss_derivative(Y_hat, Y):
    return 2 * (Y_hat - Y) / Y.size

def cross_entropy_loss(Y_hat, Y):
    m = Y.shape[0]
    log_likelihood = -np.log(np.sum(Y_hat * Y, axis=1))
    loss = np.sum(log_likelihood) / m
    return loss

def one_hot_encode(y, num_classes):
    one_hot = np.zeros((len(y), num_classes))
    one_hot[np.arange(len(y)), y] = 1
    return one_hot

