import numpy as np

class Layer:
    def __init__(self, input_size, output_size, activation=None):
        self.weights = np.random.randn(input_size, output_size) * 0.01
        self.bias = np.zeros((1, output_size))
        self.activation = activation
        self.input = None
        self.output = None
        self.weights_gradient = None
        self.bias_gradient = None

    def forward(self, input_data):
        self.input = input_data
        self.output = np.dot(input_data, self.weights) + self.bias
        if self.activation:
            self.output = self.activation.forward(self.output)
        return self.output

    def backward(self, output_gradient, learning_rate):
        if self.activation:
            output_gradient = self.activation.backward(output_gradient)

        self.weights_gradient = np.dot(self.input.T, output_gradient)
        self.bias_gradient = np.sum(output_gradient, axis=0, keepdims=True)

        input_gradient = np.dot(output_gradient, self.weights.T)

        self.weights -= learning_rate * self.weights_gradient
        self.bias -= learning_rate * self.bias_gradient

        return input_gradient

class Activation:
    def __init__(self, activation_type='relu'):
        self.activation_type = activation_type
        self.input = None
        self.output = None

    def forward(self, input_data):
        self.input = input_data
        if self.activation_type == 'relu':
            self.output = np.maximum(0, input_data)
        elif self.activation_type == 'sigmoid':
            self.output = 1 / (1 + np.exp(-input_data))
        elif self.activation_type == 'tanh':
            self.output = np.tanh(input_data)
        else:
            raise ValueError("Unsupported activation function")
        return self.output

    def backward(self, output_gradient):
        if self.activation_type == 'relu':
            return output_gradient * (self.input > 0)
        elif self.activation_type == 'sigmoid':
            sigmoid = self.output
            return output_gradient * sigmoid * (1 - sigmoid)
        elif self.activation_type == 'tanh':
            return output_gradient * (1 - self.output**2)
        else:
            raise ValueError("Unsupported activation function")

class NeuralNetwork:
    def __init__(self, layer_sizes, activations=None):
        self.layers = []
        for i in range(len(layer_sizes) - 1):
            activation = None
            if activations and i < len(activations):
                activation = Activation(activations[i])
            self.layers.append(Layer(layer_sizes[i], layer_sizes[i+1], activation))

    def forward(self, input_data):
        output = input_data
        for layer in self.layers:
            output = layer.forward(output)
        return output

    def backward(self, output_gradient, learning_rate):
        gradient = output_gradient
        for layer in reversed(self.layers):
            gradient = layer.backward(gradient, learning_rate)

    def train(self, X, y, learning_rate, epochs, loss_function='mse'):
        for epoch in range(epochs):
            # Forward pass
            predictions = self.forward(X)

            # Calculate loss
            if loss_function == 'mse':
                loss = np.mean((predictions - y)**2)
                output_gradient = 2 * (predictions - y) / len(y)
            elif loss_function == 'cross_entropy':
                loss = self.cross_entropy_loss(predictions, y)
                output_gradient = self.cross_entropy_gradient(predictions, y)
            else:
                raise ValueError("Unsupported loss function")

            # Backward pass
            self.backward(output_gradient, learning_rate)

            if (epoch + 1) % (epochs/10) == 0:
                print(f"Epoch {epoch + 1}, Loss: {loss}")

    def predict(self, X):
        return self.forward(X)

    def cross_entropy_loss(self, predictions, labels):
        epsilon = 1e-12
        predictions = np.clip(predictions, epsilon, 1. - epsilon)
        n = predictions.shape[0]
        loss = -np.sum(labels * np.log(predictions) + (1 - labels) * np.log(1 - predictions)) / n
        return loss

    def cross_entropy_gradient(self, predictions, labels):
        epsilon = 1e-12
        predictions = np.clip(predictions, epsilon, 1. - epsilon)
        return (predictions - labels) / (predictions * (1 - predictions))

